$(function () {
    // Fungsi load statisik billboard
    function loadStats() {}

    // Inisialisasi data tabel billboard-sewa
    TableHelper.init("#tableBillboardSewa", {
        ajax: window.routes.dataTable, // Mengambil endpoint url data tabel dari global window variabel
        order: [[1, "asc"]], // Urut berdasarkan kolom yang ditentukan
        filters: [3, 5], // Filter untuk Periode & Jenis saja
        urlOpsiFilter: window.routes.opsiFilter, // Mengambil endpoint url opsi filter dari global window variabel
        buttons: [{ text: "Excel" }],
        columns: [
            {
                data: "id",
                title: "ID",
                className: "dt-head-center dt-body-center",
            },
            {
                data: "judul",
                title: "Billboard",
                className: "dt-head-center",
            },
            {
                data: "countdown",
                title: "Sisa Masa Sewa",
                className: "dt-head-center",
                orderable: false,
                render: TableHelper.tabelHitungMundur,
            },
            {
                data: "periode",
                title: "Periode",
                className: "dt-head-center",
                render: (data, type) => `${data} bulan`,
            },
            {
                data: "lokasi",
                title: "Lokasi",
                className: "dt-head-center",
            },
            {
                data: "jenis",
                title: "Jenis",
                className: "dt-head-center dt-body-center",
            },
            {
                data: "tgl_awal",
                title: "Mulai",
                className: "dt-head-center dt-body-center",
                orderable: false,
                render: TableHelper.tabelTanggalWaktu,
            },
            {
                data: "tgl_akhir",
                title: "Berakhir",
                className: "dt-head-center dt-body-center",
                orderable: false,
                render: TableHelper.tabelTanggalWaktu,
            },
        ],
        columnDefs: [],
    });
});